package gcas_single
public
	with base_types;
	with gcas_nodes;

	system GCAS_singleton
		features
			altitude: in data port real;
			timeToRecovery: out data port real;
	annex agree {**
	  assume "initial_t_value": t = 0.0;
	  assume "step_size": delta_t = 0.1;
	  const "minHeightAllowed": real = 200.0;
	  const "recovery_time": real = 3.7;
	  guarantee "height_greater_than_min": (t >= 3.7) => (height > minHeightAllowed);
	  guarantee "pull_up_trend": (t >= 3.7) => (height > prev_height);
	  guarantee "recovery_time_output": timeToRecovery = recovery_time;
	**};
	end GCAS_singleton;

	system implementation GCAS_singleton.impl
	end GCAS_singleton.impl;


	-- Type Aliases

	data int extends base_types::Integer
	end int;

	data real extends base_types::Float
	end real;

	data bool extends base_types::Boolean
	end bool;

end gcas_single;

